import { useState, useEffect, useRef } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { Terminal, Send, CheckCircle2, ChevronRight, Cpu } from 'lucide-react';

gsap.registerPlugin(ScrollTrigger);

const ContactTerminal = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });
  const [isSubmitted, setIsSubmitted] = useState(false);

  const terminalRef = useRef(null);
  const cursorRef = useRef(null);

  useEffect(() => {
    let ctx = gsap.context(() => {
      // Blinking cursor animation
      gsap.to(cursorRef.current, {
        opacity: 0,
        duration: 0.6,
        repeat: -1,
        yoyo: true,
        ease: "power2.inOut"
      });

      // Terminal entrance
      gsap.from(terminalRef.current, {
        scrollTrigger: {
          trigger: terminalRef.current,
          start: "top 85%",
          toggleActions: "play none none reverse",
          invalidateOnRefresh: true,
        },
        opacity: 0,
        y: 80,
        rotateX: -20,
        scale: 0.95,
        duration: 1.5,
        ease: "expo.out"
      });

      // Ensure ScrollTrigger refreshes
      setTimeout(() => ScrollTrigger.refresh(), 1000);
    }, terminalRef);

    return () => ctx.revert();
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setIsSubmitted(true);

    // Simulate terminal processing
    const tl = gsap.timeline();
    tl.to(".terminal-line", { opacity: 0, stagger: 0.05, duration: 0.5, filter: "blur(5px)" })
      .to(".success-msg", { opacity: 1, y: 0, duration: 1, ease: "expo.out", filter: "blur(0px)" });
  };

  return (
    <section id="contact" className="bg-sand-dune section-padding relative overflow-hidden">
      <div className="container mx-auto max-w-5xl">
        <div className="text-center mb-24 space-y-6">
          <div className="inline-block px-4 py-1 bg-pine-teal/5 rounded-full text-pine-teal text-[10px] font-black uppercase tracking-[0.4em] mb-2">
            Direct Line
          </div>
          <h2 className="text-5xl md:text-7xl font-bold text-pine-teal tracking-tighter">
            Initiate Contact
          </h2>
          <div className="w-40 h-1.5 bg-pine-teal mx-auto rounded-full" />
        </div>

        <div 
          ref={terminalRef}
          className="bg-pine-teal rounded-[3rem] shadow-[0_50px_100px_-20px_rgba(8,44,45,0.4)] overflow-hidden border-[12px] border-dark-teal/30 min-h-[600px] flex flex-col perspective-1000"
        >
          {/* Terminal Header */}
          <div className="bg-dark-teal/60 px-10 py-5 flex items-center justify-between border-b border-white/5 backdrop-blur-md">
            <div className="flex gap-3">
              <div className="w-3.5 h-3.5 rounded-full bg-[#FF5F56] shadow-inner" />
              <div className="w-3.5 h-3.5 rounded-full bg-[#FFBD2E] shadow-inner" />
              <div className="w-3.5 h-3.5 rounded-full bg-[#27C93F] shadow-inner" />
            </div>
            <div className="flex items-center gap-3 text-pale-oak/40 text-[10px] font-black uppercase tracking-[0.3em]">
              <Cpu size={14} className="animate-pulse" />
              CORE-SYSTEM-SECURE — 80x24 — BASH
            </div>
            <div className="w-16 h-1.5 bg-white/5 rounded-full" />
          </div>

          {/* Terminal Body */}
          <div className="p-10 md:p-16 font-mono text-pale-oak flex-grow relative overflow-hidden bg-gradient-to-b from-transparent to-dark-teal/20">
            {/* Scanline Effect */}
            <div className="absolute inset-0 pointer-events-none bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.1)_50%),linear-gradient(90deg,rgba(255,0,0,0.03),rgba(0,255,0,0.01),rgba(0,0,255,0.03))] z-20 bg-[length:100%_4px,3px_100%]" />

            {!isSubmitted ? (
              <form onSubmit={handleSubmit} className="space-y-12 relative z-10">
                <div className="terminal-line flex flex-col md:flex-row md:items-center gap-6">
                  <div className="flex items-center text-emerald-400">
                    <ChevronRight size={24} className="mr-1" />
                    <span className="font-black uppercase text-sm tracking-widest">visitor_name:</span>
                  </div>
                  <input 
                    type="text" 
                    name="name"
                    required
                    value={formData.name}
                    onChange={handleChange}
                    className="bg-transparent border-none outline-none flex-grow text-pale-oak caret-transparent focus:ring-0 p-0 text-2xl font-bold placeholder:opacity-10"
                    autoFocus
                    placeholder="..."
                  />
                </div>

                <div className="terminal-line flex flex-col md:flex-row md:items-center gap-6">
                  <div className="flex items-center text-emerald-400">
                    <ChevronRight size={24} className="mr-1" />
                    <span className="font-black uppercase text-sm tracking-widest">visitor_email:</span>
                  </div>
                  <input 
                    type="email" 
                    name="email"
                    required
                    value={formData.email}
                    onChange={handleChange}
                    className="bg-transparent border-none outline-none flex-grow text-pale-oak caret-transparent focus:ring-0 p-0 text-2xl font-bold placeholder:opacity-10"
                    placeholder="..."
                  />
                </div>

                <div className="terminal-line flex flex-col gap-6">
                  <div className="flex items-center text-emerald-400">
                    <ChevronRight size={24} className="mr-1" />
                    <span className="font-black uppercase text-sm tracking-widest">message_payload:</span>
                  </div>
                  <textarea 
                    name="message"
                    required
                    value={formData.message}
                    onChange={handleChange}
                    rows="4"
                    className="bg-transparent border-none outline-none w-full text-pale-oak caret-transparent focus:ring-0 p-0 text-2xl font-bold resize-none placeholder:opacity-10 leading-relaxed"
                    placeholder="Type your transmission here..."
                  />
                </div>

                <div className="terminal-line flex flex-col md:flex-row items-start md:items-center justify-between pt-10 gap-8">
                  <div className="flex items-center gap-3 opacity-40 italic text-xs font-black tracking-widest">
                    {formData.name ? <span>{formData.name.toLowerCase().replace(/\s/g, '_')}@aniket_shukla:~$ </span> : <span>root@aniket_shukla:~$ </span>}
                    <div ref={cursorRef} className="w-3.5 h-7 bg-emerald-400 shadow-[0_0_15px_rgba(52,211,153,0.5)]" />
                  </div>

                  <button 
                    type="submit"
                    className="flex items-center gap-4 bg-emerald-500/10 hover:bg-emerald-500 text-emerald-400 hover:text-dark-teal px-10 py-5 rounded-2xl border-2 border-emerald-500/30 transition-all font-black uppercase tracking-[0.2em] text-xs group shadow-2xl hover:shadow-emerald-500/20"
                  >
                    Send Transmission
                    <Send size={20} className="group-hover:translate-x-2 group-hover:-translate-y-2 transition-transform duration-500" />
                  </button>
                </div>
              </form>
            ) : (
              <div className="success-msg opacity-0 translate-y-20 flex flex-col items-center justify-center h-full text-center space-y-10 py-20 relative z-10">
                <div className="w-32 h-32 rounded-full bg-emerald-500/10 flex items-center justify-center text-emerald-400 relative">
                  <div className="absolute inset-0 rounded-full border-2 border-emerald-500/20 animate-ping" />
                  <CheckCircle2 size={72} strokeWidth={1} />
                </div>
                <div className="space-y-4">
                  <h3 className="text-4xl font-bold text-pale-oak tracking-tighter">SUCCESS: TRANSMISSION RECEIVED</h3>
                  <p className="text-pale-oak/40 text-lg font-medium max-w-md mx-auto">Your message has been encrypted and successfully routed via secure protocols.</p>
                </div>
                <pre className="p-8 bg-dark-teal/50 rounded-3xl text-[10px] text-left w-full max-w-lg border-2 border-white/5 opacity-40 font-mono leading-relaxed">
                  {`> UPLOADING_PAYLOAD [##########] 100%\n> ENCRYPTING_DATA... DONE\n> ROUTING_TO_BKP_NODE... COMPLETE\n> STATUS: 200 OK\n> REF_ID: ${Math.random().toString(36).substr(2, 9).toUpperCase()}\n> RESPONSE: ACKNOWLEDGED.`}
                </pre>
                <button 
                  onClick={() => {
                    setIsSubmitted(false);
                    setFormData({ name: '', email: '', message: '' });
                  }}
                  className="text-emerald-400 font-black text-xs uppercase tracking-[0.4em] hover:text-pale-oak transition-colors mt-4"
                >
                  [ RE-INITIATE ]
                </button>
              </div>
            )}
          </div>

          {/* Footer Info */}
          <div className="p-8 bg-dark-teal/40 text-pale-oak/10 text-[9px] uppercase font-black tracking-[0.4em] flex flex-wrap justify-center gap-x-16 border-t border-white/5">
            <span>Lat: 28.6139° N</span>
            <span>Lng: 77.2090° E</span>
            <span>Node: AS-01-PROD</span>
            <span>Uptime: 99.9%</span>
          </div>
        </div>
      </div>
    </section>
  );
};

export default ContactTerminal;

import { useEffect, useRef } from 'react';
import gsap from 'gsap';
import { Github, Linkedin, FileText, Mail } from 'lucide-react';

const Hero = () => {
  const sectionRef = useRef(null);
  const textRef = useRef(null);
  const imageRef = useRef(null);

  useEffect(() => {
    const ctx = gsap.context(() => {
      // Stagger text entrance
      gsap.from(".hero-text-item", {
        opacity: 0,
        y: 30,
        stagger: 0.1,
        duration: 1,
        ease: "power3.out",
        delay: 0.5
      });

      // Profile image entrance
      gsap.from(imageRef.current, {
        opacity: 0,
        scale: 0.8,
        duration: 1.2,
        ease: "back.out(1.7)",
        delay: 0.8
      });

      // Slow floating animation for image
      gsap.to(imageRef.current, {
        y: 15,
        duration: 2.5,
        repeat: -1,
        yoyo: true,
        ease: "power1.inOut"
      });
    }, sectionRef);

    return () => ctx.revert();
  }, []);

  return (
    <section 
      ref={sectionRef}
      className="min-h-screen flex items-center justify-center bg-sand-dune section-padding relative overflow-hidden"
    >
      {/* Decorative background element */}
      <div className="absolute -top-24 -right-24 w-96 h-96 bg-pine-teal/5 rounded-full blur-3xl" />
      <div className="absolute -bottom-24 -left-24 w-96 h-96 bg-pale-oak/50 rounded-full blur-3xl" />

      <div className="container mx-auto grid grid-cols-1 lg:grid-cols-2 gap-12 items-center z-10">
        {/* Left Content */}
        <div className="space-y-6 text-center lg:text-left">
          <div className="space-y-2">
            <h2 className="hero-text-item text-pine-teal/80 text-xl md:text-2xl font-medium tracking-tight">
              Hello, I'm
            </h2>
            <h1 className="hero-text-item text-6xl md:text-8xl font-bold text-pine-teal tracking-tighter leading-none">
              ANIKET <br /> SHUKLA
            </h1>
          </div>

          <p className="hero-text-item text-lg md:text-xl text-pine-teal/70 max-w-xl leading-relaxed">
            A passionate Full Stack Developer dedicated to building premium digital experiences that combine innovative design with robust engineering.
          </p>

          <div className="hero-text-item flex flex-wrap justify-center lg:justify-start gap-4 pt-4">
            <a 
              href="/AniketShuklaCVFinal.pdf" 
              download
              className="btn-primary flex items-center gap-2 group"
            >
              <FileText size={20} className="group-hover:rotate-12 transition-transform" />
              Download Resume
            </a>

            <div className="flex items-center gap-3">
              {[
                { icon: <Github size={24} />, href: "https://github.com/theRoutines" },
                { icon: <Linkedin size={24} />, href: "https://linkedin.com/in/aniketshuklacse" },
                { icon: <Mail size={24} />, href: "mailto:aniketshukla933@gmail.com" }
              ].map((social, idx) => (
                <a 
                  key={idx}
                  href={social.href}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="w-12 h-12 rounded-full border border-pine-teal/20 flex items-center justify-center text-pine-teal hover:bg-pine-teal hover:text-sand-dune transition-colors"
                >
                  {social.icon}
                </a>
              ))}
            </div>
          </div>
        </div>

        {/* Right Content - Image */}
        <div className="flex justify-center items-center">
          <div 
            ref={imageRef}
            className="relative w-64 h-64 md:w-96 md:h-96"
          >
            {/* Image Border/Frame */}
            <div className="absolute inset-0 border-2 border-pine-teal/10 rounded-[3rem] rotate-6 transform translate-x-4 translate-y-4" />

            <div className="absolute inset-0 bg-pale-oak rounded-[3rem] shadow-2xl overflow-hidden border-2 border-pine-teal/5">
              <img 
                src="/avatar.png" 
                alt="Aniket Shukla" 
                className="w-full h-full object-cover grayscale-[20%] hover:grayscale-0 transition-all duration-500"
              />
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
